#include <bits/stdc++.h>
using namespace std;

const int N=2e5+5;

int n,m,f[N],siz[N];
long long ans[N];
char s[N];
vector<int> g[N];

int father(int x){
    return (f[x]==x?x:f[x]=father(f[x]));
}

long long merge(int x,int y){
    int fx=father(x),fy=father(y);
    if(fx!=fy){
        int tmp=siz[fx];
        f[fy]=fx,siz[fx]+=siz[fy];
        return 1LL*tmp*siz[fy];
    }
    return 0;
}

int main(){
    scanf("%d%d",&n,&m);
    scanf("%s",s+1);
    for(int i=1,u,v;i<=m;i++){
        scanf("%d%d",&u,&v);
        g[u].push_back(v);
        g[v].push_back(u);
    }

    for(int i=1;i<=n;i++)
        f[i]=i,siz[i]=(s[i]=='0');
    for(int i=1;i<=n;i++)
        if(s[i]=='1'){
            int len=g[i].size();
            for(int j=0;j<len;j++)
                if(s[g[i][j]]=='1')
                    merge(i,g[i][j]);
        }
    for(int i=n;i;i--){
        ans[i]=ans[i+1];
        if(s[i]=='0'){
            int len=g[i].size();
            for(int j=0;j<len;j++)
                if(s[g[i][j]]=='1' || g[i][j]>i)
                    ans[i]+=merge(i,g[i][j]);
        }else
            ans[i]+=siz[father(i)]++;
    }
    for(int i=1;i<=n;i++)
        printf("%lld\n",ans[i]);
    return 0;
}
